import React, { useState } from 'react';
import './App.css';
import Item from './component/Item';


function App() {
  const [items, setItems] = useState([{ name: "Phone", price: 1500, amount: 0 }, { name: "Laptop", price: 3500, amount: 0 }, { name: "Tablet", price: 2000, amount: 0 }, { name: "Smart Watch", price: 1000, amount: 0 }, { name: "Headphones", price: 1500, amount: 0 }])
  const [total, setTotal] = useState(0)
  let addItem = (name) => {
    items.map((item) => {
      if (item.name == name) {
        setTotal(total + item.price)
        return { name: item.name, price: item.price, amount: item.amount + 1 }
      }
      else return { name: item.name, price: item.price, amount: item.amount }
    })
  }

  let delteItem = (name) => {
    items.map((item) => {
      if (item.name == name && item.amount > 0) {
        setTotal(total - item.price)
        return { name: item.name, price: item.price, amount: item.amount - 1 }
      }
      else return { name: item.name, price: item.price, amount: item.amount }
    })
  }


  return (
    <div className="App">
      <div className="App">
        <h1></h1>
        <div></div>
        {items.map((i) => { return <Item info={i} add={addItem} remove={delteItem} /> })}


      </div>
    </div>
  );
}

export default App;
